module fixed_priority_arbiter(  
    input wire req0,  
    input wire req1,  
    input wire req2,  
    input wire req3,  
    output reg [3:0] obf_grant  
);  
    always @(*) begin  
        obf_grant = 4'b0000;  
        if (req0) obf_grant = 4'b0001;  
        else if (req1) obf_grant = 4'b0010;  
        else if (req2) obf_grant = 4'b0100;  
        else if (req3) obf_grant = 4'b1000;  
    end  
endmodule
